CREATE VIEW public.v_funnel_analytics AS
 SELECT m.client_id,
    m.visit_datetime,
    COALESCE(m.utm_source, 'direct'::character varying) AS utm_source,
    COALESCE(m.utm_medium, 'none'::character varying) AS utm_medium,
    COALESCE(m.utm_campaign, 'none'::character varying) AS utm_campaign,
    b.log_datetime,
    b.api_method,
    b.status_code AS backend_status,
    c.lead_id,
    c.created_datetime AS lead_created_at,
    c.current_status AS status_1c,
    c.revenue
   FROM ((public.raw_metrika m
     LEFT JOIN public.raw_backend_logs b ON (((m.client_id)::text = (b.client_id)::text)))
     LEFT JOIN public.raw_1c_leads c ON (((b.user_guid)::text = (c.user_guid)::text)));


